use std::io::*;

fn read<T: std::str::FromStr>(i: &mut StdinLock) -> T {
    let mut s = String::new();
    i.by_ref().read_line(&mut s).ok();
    s.trim().parse().ok().unwrap()
}

fn main() {
    // initialize stdin
    let sin = std::io::stdin();
    let mut sin = sin.lock();
    let sin = &mut sin;

    let zandaka: String = read(sin);

    if Some('-') != zandaka.as_str().chars().nth(0) {
        println!("{}", zandaka);
        return;
    }

    let remove_last: String = zandaka
        .as_str()
        .chars()
        .enumerate()
        .filter(|(idx, _c)| *idx != (zandaka.len() - 1))
        .map(|(_idx, c)| c)
        .collect();

    let rl_num: i64 = remove_last.parse().unwrap();
    let moto: i64 = zandaka.parse().unwrap();

    let mut cmax = std::cmp::max(moto, rl_num);

    if 2 < zandaka.len() {
        let remove_before_last: String = zandaka
            .as_str()
            .chars()
            .enumerate()
            .filter(|(idx, _c)| *idx != (zandaka.len() - 2))
            .map(|(_idx, c)| c)
            .collect();

        let rbl_num: i64 = remove_before_last.parse().unwrap();

        cmax = std::cmp::max(cmax, rbl_num);
    }

    println!("{}", cmax)
}
